import React, { useRef, useMemo, useState, useEffect } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import "../style/SkillConstellation.css";

/* ════════════════════════════════════════
   Orbital Skill System — solar-system layout
   Inner orbits = core skills (faster)
   Outer orbits = specialised skills (slower)
════════════════════════════════════════ */
const ORBITS = [
  { name: "Core Languages", color: "#fbbf24", radius: 1.3, speed: 0.42, tilt: 0.20,
    skills: ["Python", "SQL"],                        nodeR: 0.14 },
  { name: "Data Tools",     color: "#60a5fa", radius: 2.35, speed: 0.24, tilt: 0.55,
    skills: ["PostgreSQL", "pandas", "psycopg2", "Spark"], nodeR: 0.11 },
  { name: "Backend / API",  color: "#34d399", radius: 3.3, speed: 0.15, tilt: 0.85,
    skills: ["FastAPI", "WebSocket", "APScheduler", "Docker", "FAISS"], nodeR: 0.10 },
  { name: "ML / AI",        color: "#a78bfa", radius: 4.25, speed: 0.09, tilt: 1.10,
    skills: ["XGBoost", "scikit-learn", "PyTorch", "sent-trans", "Kubernetes"], nodeR: 0.095 },
];

/* ── Central spinning core ── */
function CoreNode() {
  const ref = useRef();
  useFrame(({ clock }) => {
    if (!ref.current) return;
    ref.current.rotation.y = clock.elapsedTime * 0.4;
    ref.current.rotation.x = clock.elapsedTime * 0.25;
  });
  return (
    <group>
      {/* Wireframe icosahedron */}
      <mesh ref={ref}>
        <icosahedronGeometry args={[0.24, 1]} />
        <meshBasicMaterial color="#ffffff" wireframe transparent opacity={0.9} />
      </mesh>
      {/* Inner glow */}
      <mesh>
        <sphereGeometry args={[0.38, 14, 14]} />
        <meshBasicMaterial color="#ffffff" transparent opacity={0.12}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
      {/* Outer bloom */}
      <mesh>
        <sphereGeometry args={[0.65, 14, 14]} />
        <meshBasicMaterial color="#aaaaff" transparent opacity={0.045}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
    </group>
  );
}

/* ── Orbit ring path (tilted torus) ── */
function OrbitRing({ radius, tilt, color }) {
  return (
    <mesh rotation={[tilt, 0, 0]}>
      <torusGeometry args={[radius, 0.007, 6, 120]} />
      <meshBasicMaterial color={color} transparent opacity={0.18} />
    </mesh>
  );
}

/* ── Single skill node (pulsing glow sphere) ── */
function SkillNode({ position, color, r }) {
  const groupRef = useRef();
  const phase = useRef(Math.random() * Math.PI * 2);
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    const s = 1 + Math.sin(clock.elapsedTime * 1.9 + phase.current) * 0.12;
    groupRef.current.scale.setScalar(s);
  });
  return (
    <group ref={groupRef} position={position}>
      <mesh>
        <sphereGeometry args={[r, 12, 12]} />
        <meshBasicMaterial color={color} />
      </mesh>
      <mesh>
        <sphereGeometry args={[r * 2.1, 12, 12]} />
        <meshBasicMaterial color={color} transparent opacity={0.16}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
      <mesh>
        <sphereGeometry args={[r * 3.8, 12, 12]} />
        <meshBasicMaterial color={color} transparent opacity={0.05}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
    </group>
  );
}

/* ── Rotating group of nodes on one orbit ── */
function OrbitGroup({ color, radius, speed, tilt, skills, nodeR }) {
  const rotRef = useRef();
  useFrame(({ clock }) => {
    if (rotRef.current) rotRef.current.rotation.y = clock.elapsedTime * speed;
  });

  const positions = skills.map((_, i) => {
    const angle = (i / skills.length) * Math.PI * 2;
    return [Math.cos(angle) * radius, 0, Math.sin(angle) * radius];
  });

  return (
    /* outer group handles tilt; inner group handles rotation */
    <group rotation={[tilt, 0, 0]}>
      <group ref={rotRef}>
        {skills.map((skill, i) => (
          <SkillNode key={skill} position={positions[i]} color={color} r={nodeR} />
        ))}
      </group>
    </group>
  );
}

/* ── Ambient background stars ── */
function BgStars() {
  const geo = useMemo(() => {
    const COUNT = 700;
    const pos = new Float32Array(COUNT * 3);
    for (let i = 0; i < COUNT; i++) {
      pos[i * 3]     = (Math.random() - 0.5) * 24;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 14;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 8 - 4;
    }
    const g = new THREE.BufferGeometry();
    g.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    return g;
  }, []);
  return (
    <points geometry={geo}>
      <pointsMaterial color="#8899cc" size={0.013} transparent opacity={0.28} sizeAttenuation />
    </points>
  );
}

/* ── Full orbital scene ── */
function OrbitalScene() {
  const sceneRef = useRef();
  useFrame(({ clock }) => {
    if (!sceneRef.current) return;
    // Slow overall tilt oscillation for depth feel
    sceneRef.current.rotation.x = 0.32 + Math.sin(clock.elapsedTime * 0.08) * 0.06;
  });

  return (
    <group ref={sceneRef}>
      <BgStars />
      <CoreNode />
      {ORBITS.map((orbit) => (
        <React.Fragment key={orbit.name}>
          <OrbitRing radius={orbit.radius} tilt={orbit.tilt} color={orbit.color} />
          <OrbitGroup {...orbit} />
        </React.Fragment>
      ))}
    </group>
  );
}

/* ── Lazy-mount wrapper ── */
function LazyCanvas({ children, ...props }) {
  const wrapRef = useRef();
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (wrapRef.current) obs.observe(wrapRef.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={wrapRef} style={{ width: "100%", height: "100%" }}>
      {visible && <Canvas {...props}>{children}</Canvas>}
    </div>
  );
}

const SkillConstellation = () => (
  <div className="constellation-wrap">
    <div className="constellation-canvas" aria-hidden="true">
      <LazyCanvas
        camera={{ position: [0, 4, 12], fov: 52 }}
        gl={{ antialias: true, alpha: false }}
        onCreated={({ gl }) => gl.setClearColor("#010108", 1)}
      >
        <OrbitalScene />
      </LazyCanvas>
    </div>
    <div className="constellation-legend">
      {ORBITS.map((o) => (
        <div key={o.name} className="constellation-legend-item">
          <span className="constellation-dot" style={{ background: o.color }} />
          {o.name}
        </div>
      ))}
    </div>
  </div>
);

export default SkillConstellation;
